import React from 'react';

interface CouponCardProps {
  title: string;
  expiry: string;
  maxDiscount: number;
  discountRate: number;
  onUse: () => void;
}

const CouponCard: React.FC<CouponCardProps> = ({ title, expiry, maxDiscount, discountRate, onUse }) => {
  return (
    <div className="relative border rounded-lg p-4 flex flex-col gap-2 bg-gray-100 overflow-visible">
      <div className="flex flex-col justify-between items-center px-2">
        <div className="flex flex-col w-full">
          <div className="font-semibold mb-1">{title}</div>
          <div className="text-xs text-gray-500">{expiry}</div>
          <div className="text-xs text-gray-400">(최대 {maxDiscount.toLocaleString()}원 할인)</div>
        </div>
        <div className="flex flex-row items-center justify-between w-full mt-4">
          <div className="text-orange-600 font-bold text-sm">사용 가능</div>
          <div className="text-blue-600 font-bold text-sm">{discountRate}%</div>
        </div>
      </div>
      <button
        className="w-full bg-orange-600 text-white py-2 rounded-lg font-semibold hover:bg-orange-700 transition mt-4"
        onClick={onUse}
      >
        쿠폰 사용
      </button>
      {/* 쿠폰 하단 이미지 효과 */}
      <div className="relative h-6 mt-2">
        <div className="absolute left-0 -top-2 w-6 h-6 bg-white rounded-full border border-gray-200 z-10 flex items-center justify-center">
          <div className="w-3 h-3 rounded-full bg-gray-100"></div>
        </div>
        <div className="absolute right-0 -top-2 w-6 h-6 bg-white rounded-full border border-gray-200 z-10 flex items-center justify-center">
          <div className="w-3 h-3 rounded-full bg-gray-100"></div>
        </div>
        <div className="absolute left-3 right-3 top-1/2 border-b-2 border-dashed border-gray-300 z-0"></div>
      </div>
    </div>
  );
};

export default CouponCard;
